let editingSheetId=null;
function openSheetModal(editId){editingSheetId=editId||null;document.getElementById('sheetModalTitle').textContent=editId?'Edit Sheet':'New Sheet';document.getElementById('sheetModalSave').textContent=editId?'Save':'Create';const sh=editId?getSheet(editId):null;document.getElementById('sheetNameInput').value=sh?sh.name:'';const row=document.getElementById('colorRow');row.innerHTML=COLORS.map(c=>'<div class="mn-color-swatch'+(sh&&sh.color===c?' selected':(!sh&&c===COLORS[S.sheets.length%COLORS.length]?' selected':''))+'" style="background:'+c+'" data-color="'+c+'" onclick="pickColor(this)"></div>').join('');document.getElementById('sheetModalOverlay').classList.add('active');document.getElementById('sheetNameInput').focus();}
function closeSheetModal(){document.getElementById('sheetModalOverlay').classList.remove('active');editingSheetId=null;}
function pickColor(el){document.querySelectorAll('.mn-color-swatch').forEach(s=>s.classList.remove('selected'));el.classList.add('selected');}
function saveSheetModal(){const name=document.getElementById('sheetNameInput').value.trim();if(!name){toast('Enter a name.',true);return;}const sel=document.querySelector('.mn-color-swatch.selected');const color=sel?sel.dataset.color:COLORS[0];if(editingSheetId){const sh=getSheet(editingSheetId);sh.name=name;sh.color=color;}else{const id='sheet_'+Date.now();S.sheets.push({id,name,color,builtIn:false,sections:[{id:'s1',name:'Patient Information',instructions:'Name, Age, Gender, Date.',rules:''},{id:'s2',name:'Chief Complaint',instructions:'Primary reason.',rules:''},{id:'s3',name:'History of Present Illness',instructions:'Detailed narrative.',rules:''},{id:'s4',name:'Physical Examination',instructions:'Complete exam.',rules:''},{id:'s5',name:'Assessments',instructions:'Numbered assessments.',rules:''},{id:'s6',name:'Plan',instructions:'Numbered plan items.',rules:''}],options:{...DOPTS,generalRules:DEF_GENERAL_RULES}});switchMode(id);}saveS(S);renderModeTabs();updateFilterTypeOptions();closeSheetModal();toast(editingSheetId?'Sheet updated.':'Sheet created.');}
function deleteSheet(id){const sh=getSheet(id);if(sh.builtIn){toast('Cannot delete built-in sheets.',true);return;}showConfirm('Delete sheet <strong>"'+esc(sh.name)+'"</strong> and all its prompt config? Cases in history will remain.',ok=>{if(!ok)return;S.sheets=S.sheets.filter(s=>s.id!==id);if(currentSheetId===id)switchMode(S.sheets[0].id);saveS(S);renderModeTabs();updateFilterTypeOptions();toast('Sheet deleted.');});}

