function loadPBO(){const o=gOpts();document.getElementById('pbOptAbnormal').checked=!!o.abnormalOnly;document.getElementById('pbOptBullets').checked=!!o.bullets;document.getElementById('pbOptNarrative').checked=!!o.narrative;document.getElementById('pbOptDetail').value=o.detail||'medium';document.getElementById('pbOptMissing').value=o.missing||'Not provided';document.getElementById('pbGeneralRules').value=o.generalRules!=null?o.generalRules:DEF_GENERAL_RULES;const t=o.typo||DOPTS.typo;const h2=t.h2||{size:16,bold:true,color:'#000000',underline:false};const st=t.strong||{size:14,bold:true,color:'#000000',underline:false};const pp=t.p||{size:14,bold:false,color:'#000000',underline:false};if(typeof h2==='number'){document.getElementById('typoH2').value=h2;document.getElementById('typoH2Bold').checked=true;document.getElementById('typoH2Color').value='#000000';document.getElementById('typoH2Under').checked=false;document.getElementById('typoStrong').value=typeof st==='number'?st:14;document.getElementById('typoStrongBold').checked=true;document.getElementById('typoStrongColor').value='#000000';document.getElementById('typoStrongUnder').checked=false;document.getElementById('typoP').value=typeof pp==='number'?pp:14;document.getElementById('typoPBold').checked=false;document.getElementById('typoPColor').value='#000000';document.getElementById('typoPUnder').checked=false;}else{document.getElementById('typoH2').value=h2.size||16;document.getElementById('typoH2Bold').checked=h2.bold!==false;document.getElementById('typoH2Color').value=h2.color||'#000000';document.getElementById('typoH2Under').checked=!!h2.underline;document.getElementById('typoStrong').value=st.size||14;document.getElementById('typoStrongBold').checked=st.bold!==false;document.getElementById('typoStrongColor').value=st.color||'#000000';document.getElementById('typoStrongUnder').checked=!!st.underline;document.getElementById('typoP').value=pp.size||14;document.getElementById('typoPBold').checked=!!pp.bold;document.getElementById('typoPColor').value=pp.color||'#000000';document.getElementById('typoPUnder').checked=!!pp.underline;}document.getElementById('typoFontFamily').value=o.fontFamily||'Arial, sans-serif';}
function savePBO(){const o=gOpts();o.abnormalOnly=document.getElementById('pbOptAbnormal').checked;o.bullets=document.getElementById('pbOptBullets').checked;o.narrative=document.getElementById('pbOptNarrative').checked;o.detail=document.getElementById('pbOptDetail').value;o.missing=document.getElementById('pbOptMissing').value||'Not provided';o.generalRules=document.getElementById('pbGeneralRules').value;o.fontFamily=document.getElementById('typoFontFamily').value||'Arial, sans-serif';o.typo={h2:{size:+document.getElementById('typoH2').value||16,bold:document.getElementById('typoH2Bold').checked,color:document.getElementById('typoH2Color').value,underline:document.getElementById('typoH2Under').checked},strong:{size:+document.getElementById('typoStrong').value||14,bold:document.getElementById('typoStrongBold').checked,color:document.getElementById('typoStrongColor').value,underline:document.getElementById('typoStrongUnder').checked},p:{size:+document.getElementById('typoP').value||14,bold:document.getElementById('typoPBold').checked,color:document.getElementById('typoPColor').value,underline:document.getElementById('typoPUnder').checked}};}
function renderPBS(){const secs=gSecs();const sh=gSh();document.getElementById('pbSections').innerHTML=secs.map((s,i)=>'<div class="pb-section" draggable="true" data-idx="'+i+'" ondragstart="pbDS(event)" ondragover="pbDO(event)" ondrop="pbDD(event)" ondragend="pbDE(event)" ondragleave="pbDL(event)"><div class="pb-section-header"><div class="pb-section-grip"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="9" cy="6" r="1.5"/><circle cx="15" cy="6" r="1.5"/><circle cx="9" cy="12" r="1.5"/><circle cx="15" cy="12" r="1.5"/><circle cx="9" cy="18" r="1.5"/><circle cx="15" cy="18" r="1.5"/></svg></div><div class="pb-section-num" style="background:'+sh.color+'">'+(i+1)+'</div><div class="pb-section-name">'+esc(s.name)+'</div><div class="pb-section-actions"><button onclick="tSB('+i+')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="pb-del" onclick="delSec('+i+')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg></button></div></div><div class="pb-section-body" id="pbB'+i+'"><div class="pb-field"><div class="pb-field-label">Section Name</div><input class="pb-input" value="'+esc(s.name)+'" oninput="uSec('+i+',\'name\',this.value)"></div><div class="pb-field"><div class="pb-field-label">Instructions for AI</div><textarea class="pb-textarea" oninput="uSec('+i+',\'instructions\',this.value)">'+esc(s.instructions)+'</textarea></div><div class="pb-field"><div class="pb-field-label">Rules / Conditions</div><textarea class="pb-textarea" style="min-height:45px" oninput="uSec('+i+',\'rules\',this.value)">'+esc(s.rules)+'</textarea></div></div></div>').join('');}
