function resetCurrentPB(){const sh=gSh();const label=sh.name;showConfirm('Reset <strong>all sections and options</strong> for "'+esc(label)+'" to defaults? This cannot be undone.',ok=>{if(!ok)return;const def=sh.id==='notes'?DS_NOTES:sh.id==='admission'?DS_ADM:sh.id==='progress'?DS_PROG:[{id:'s1',name:'Patient Information',instructions:'Name, Age, Gender, Date.',rules:''},{id:'s2',name:'Chief Complaint',instructions:'Primary reason.',rules:''},{id:'s3',name:'Plan',instructions:'Numbered plan items.',rules:''}];sh.sections=JSON.parse(JSON.stringify(def));sh.options={...DOPTS,generalRules:sh.id==='notes'?DEF_GENERAL_RULES_MN:sh.id==='progress'?DEF_GENERAL_RULES_PROG:sh.id==='admission'?DEF_GENERAL_RULES_ADM:DEF_GENERAL_RULES};loadPBO();renderPBS();toast('Reset to defaults.');});}
function togglePreview(){savePBO();const existing=document.getElementById('promptPreviewModal');if(existing){existing.remove();return;}const prompt=buildPrompt(pbSheetId);const sh=getSheet(pbSheetId);const modal=document.createElement('div');modal.id='promptPreviewModal';modal.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9999;display:flex;align-items:flex-start;justify-content:center;padding:28px 16px;overflow-y:auto';modal.onclick=e=>{if(e.target===modal)modal.remove();};modal.innerHTML='<div style="background:var(--surface);border:1px solid var(--border);border-radius:14px;width:100%;max-width:780px;padding:22px;position:relative;box-shadow:0 8px 40px rgba(0,0,0,.35)"><div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:16px"><div><div style="font-size:.67rem;font-weight:700;text-transform:uppercase;letter-spacing:.6px;color:var(--text-muted);margin-bottom:4px">Full Prompt Preview</div><div style="font-size:.95rem;font-weight:700;color:var(--text);display:flex;align-items:center;gap:8px"><span style="width:11px;height:11px;border-radius:50%;background:'+sh.color+';display:inline-block;flex-shrink:0"></span>'+esc(sh.name)+'</div></div><div style="display:flex;gap:8px;flex-shrink:0"><button onclick="navigator.clipboard.writeText(document.getElementById(\'promptPreviewText\').textContent).then(()=>toast(\'Prompt copied!\')).catch(()=>toast(\'Copy failed.\',true))" style="background:var(--primary-light);color:var(--primary);border:1px solid rgba(26,86,219,.2);border-radius:7px;padding:7px 13px;font-family:\'Karla\',sans-serif;font-size:.75rem;font-weight:600;cursor:pointer">Copy</button><button onclick="document.getElementById(\'promptPreviewModal\').remove()" style="background:var(--surface-warm);color:var(--text-secondary);border:1px solid var(--border);border-radius:7px;padding:7px 13px;font-family:\'Karla\',sans-serif;font-size:.75rem;font-weight:600;cursor:pointer">Close</button></div></div><pre id="promptPreviewText" style="background:var(--surface-warm);border:1px solid var(--border);border-radius:8px;padding:16px;font-family:monospace;font-size:.72rem;line-height:1.65;color:var(--text-secondary);white-space:pre-wrap;word-break:break-word;margin:0;overflow-y:auto">'+esc(prompt)+'</pre></div>';document.body.appendChild(modal);}
function pbDS(e){dragSrcIdx=+e.currentTarget.dataset.idx;e.currentTarget.classList.add('dragging');e.dataTransfer.effectAllowed='move';}
function pbDO(e){e.preventDefault();e.dataTransfer.dropEffect='move';e.currentTarget.classList.add('drag-over');}
function pbDL(e){e.currentTarget.classList.remove('drag-over');}
function pbDE(){document.querySelectorAll('.pb-section').forEach(s=>s.classList.remove('dragging','drag-over'));}
function pbDD(e){e.preventDefault();const t=+e.currentTarget.dataset.idx;e.currentTarget.classList.remove('drag-over');if(dragSrcIdx===null||dragSrcIdx===t)return;const s=gSecs(),moved=s.splice(dragSrcIdx,1)[0];s.splice(t,0,moved);renderPBS();}

