async function sendEmail(){const to=document.getElementById('emailTo').value.trim();if(!to||!to.includes('@')){toast('Enter a valid email.',true);return;}const lH=document.getElementById('reportContent').innerHTML;if(!lH.trim()){toast('No report.',true);return;}document.getElementById('btnSend').disabled=true;document.getElementById('btnSend').textContent='Sending...';try{await emailjs.send('service_juj0v5c','template_rw4cwfl',{to_email:to,subject:'Medical Report — '+(extractTitle(lH)||'Report'),report_html:lH});toast('Sent to '+to);document.getElementById('emailPanel').classList.remove('active');}catch(e){toast('Error: '+(e.text||e.message||e),true);}document.getElementById('btnSend').disabled=false;document.getElementById('btnSend').textContent='Send';}

function getLiveReportHTML(){return document.getElementById('reportContent').innerHTML;}
function getDoctorStampHTML(){const d=S.doctor||{},h=S.hospital||{};const name=d.name||'Dr. Miguel Rivas';let l=['<strong>'+esc(name)+'</strong>'];if(d.specialty)l.push(esc(d.specialty));if(d.license)l.push('License: '+esc(d.license));if(d.npi)l.push('NPI: '+esc(d.npi));if(d.phone)l.push('Tel: '+esc(d.phone));if(d.email)l.push(esc(d.email));if(h.name){l.push('');l.push('<strong>'+esc(h.name)+'</strong>');if(h.dept)l.push(esc(h.dept));if(h.address)l.push(esc(h.address));if(h.phone)l.push('Tel: '+esc(h.phone));}return l.join('<br>');}
function applyReportTypo(){const sh=curSheet();const t=sh.options?.typo||DOPTS.typo;const h2=typeof t.h2==='number'?{size:t.h2,bold:true,color:'#000000',underline:false}:t.h2;const st=typeof t.strong==='number'?{size:t.strong,bold:true,color:'#000000',underline:false}:t.strong;const pp=typeof t.p==='number'?{size:t.p,bold:false,color:'#000000',underline:false}:t.p;const rep=document.getElementById('reportContent');rep.style.fontFamily=sh.options?.fontFamily||'Arial, sans-serif';rep.querySelectorAll('h2').forEach(el=>{el.style.fontSize=h2.size+'px';el.style.fontWeight=h2.bold?'700':'400';el.style.color=h2.color||'';el.style.textDecoration=h2.underline?'underline':'none';});rep.querySelectorAll('strong').forEach(el=>{el.style.fontSize=st.size+'px';el.style.fontWeight=st.bold?'700':'400';el.style.color=st.color||'';el.style.textDecoration=st.underline?'underline':'none';});rep.querySelectorAll('p').forEach(el=>{el.style.fontSize=pp.size+'px';el.style.fontWeight=pp.bold?'700':'400';el.style.color=pp.color||'';el.style.textDecoration=pp.underline?'underline':'none';});}

document.getElementById('reportContent').addEventListener('input',function(){hasUnsavedEdits=true;structuredText=this.innerHTML;document.getElementById('btnSaveEdits').style.display='inline-flex';const ind=document.getElementById('saveIndicator');ind.classList.add('active','saving');document.getElementById('saveIndicatorText').textContent='Unsaved...';clearTimeout(saveDebounceTimer);saveDebounceTimer=setTimeout(()=>autoSave(),2000);});
async function autoSave(){if(!currentCaseId||!hasUnsavedEdits)return;try{const h=getLiveReportHTML();await saveCase(currentCaseId,extractTitle(h),currentInput,h,currentCaseType);hasUnsavedEdits=false;document.getElementById('saveIndicator').classList.remove('saving');document.getElementById('saveIndicatorText').textContent='Saved';document.getElementById('btnSaveEdits').style.display='none';renderSidebar();setTimeout(()=>document.getElementById('saveIndicator').classList.remove('active'),2500);}catch{document.getElementById('saveIndicatorText').textContent='Failed';}}
