function dismissHint(){document.getElementById('editHint').classList.remove('active');}
async function callAPI(c){const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:c}]})});if(!r.ok){const e=await r.json().catch(()=>({}));throw new Error(e.error?.message||'API error '+r.status);}const d=await r.json();let h=d.content.map(b=>b.text||'').join('');return h.replace(/```html?/g,'').replace(/```/g,'').trim();}
async function saveCase(id,title,input,output,type){await fetch(PROXY+'/save',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id,title,input,output,type:type||'notes',timestamp:Date.now()})});}
async function loadHistory(){try{return await(await fetch(PROXY+'/history')).json();}catch{return[];}}
async function deleteCase(id){await fetch(PROXY+'/history/'+id,{method:'DELETE'});}
function extractTitle(html){const t=document.createElement('div');t.innerHTML=html;for(const p of t.querySelectorAll('p')){const x=p.textContent;if((x.includes('Name:')||x.includes('name:'))&&!x.includes('Not provided')){const n=x.split(':').slice(1).join(':').trim();if(n&&n!=='Not provided')return n;}}return'Medical Report';}
function extractMeta(html){const t=document.createElement('div');t.innerHTML=html;let name='',age='',complaint='';for(const p of t.querySelectorAll('p')){const x=p.textContent.trim();if(x.startsWith('Name:'))name=x.replace('Name:','').trim();else if(x.startsWith('Age:'))age=x.replace('Age:','').trim();}for(const h2 of t.querySelectorAll('h2')){if(h2.textContent.includes('Chief Complaint')){let n=h2.nextElementSibling;if(n&&n.tagName==='P')complaint=n.textContent.trim().substring(0,100);break;}}return{name,age,complaint};}

async function renderSidebar(){const cases=await loadHistory();const list=document.getElementById('sidebarList');const fType=document.getElementById('filterType').value;const fFrom=document.getElementById('filterFrom').value;const fTo=document.getElementById('filterTo').value;const fKey=(document.getElementById('filterKeyword').value||'').trim().toLowerCase();let filtered=cases;if(fType&&fType!=='all')filtered=filtered.filter(c=>(c.type||'notes')===fType);if(fFrom){const d=new Date(fFrom).getTime();filtered=filtered.filter(c=>c.timestamp>=d);}if(fTo){const d=new Date(fTo).getTime()+86400000;filtered=filtered.filter(c=>c.timestamp<d);}if(fKey)filtered=filtered.filter(c=>{const hay=((c.title||'')+(c.input||'')+(c.output||'')).toLowerCase();return hay.includes(fKey);});
if(!filtered.length){list.innerHTML='<div class="mn-sidebar-empty">'+(cases.length?'No matching cases.':'No saved cases yet.')+'</div>';return;}
list.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp),ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric'}),ts=d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});const meta=extractMeta(c.output||'');const act=currentCaseId===c.id?' active':'';const type=c.type||'notes';const sh=getSheet(type);const color=sh?sh.color:'#888';const label=sh?sh.name.substring(0,4).toUpperCase():type.substring(0,4).toUpperCase();let mH='';if(meta.name&&meta.name!=='Not provided')mH+='<span>'+esc(meta.name)+'</span>';if(meta.complaint&&meta.complaint!=='Not provided')mH+='<span><span class="mn-meta-label">CC</span>'+esc(meta.complaint)+'</span>';const pv=c.input?esc(c.input.substring(0,80))+(c.input.length>80?'...':''):'';return'<div class="mn-sidebar-item'+act+'" onclick="loadCase(\''+c.id+'\')"><div class="mn-sidebar-item-title"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+'">'+label+'</span><span class="mn-case-title-text" id="caseTitle_'+c.id+'">'+esc(c.title||'Untitled')+'</span></div><div class="mn-sidebar-item-date">'+ds+' '+ts+'</div>'+(mH?'<div class="mn-sidebar-item-meta">'+mH+'</div>':'')+'<div class="mn-sidebar-item-preview">'+pv+'</div><div class="mn-sidebar-item-btns" onclick="event.stopPropagation()"><button class="mn-sbtn-rename" onclick="startRenameCase(\''+c.id+'\')" title="Rename">&#9998;</button><button class="mn-sbtn-regen" onclick="regenCase(\''+c.id+'\')">Re</button><button class="mn-sbtn-del" onclick="deleteCaseUI(\''+c.id+'\')">X</button></div></div>';}).join('');}

async function loadCase(id){try{autoSaveDraft();saveDraftIfNeeded();const c=await(await fetch(PROXY+'/history/'+id)).json();currentCaseId=c.id;currentInput=c.input;structuredText=c.output;reportGenerated=true;hasUnsavedEdits=false;currentCaseType=c.type||'notes';if(S.sheets.find(s=>s.id===currentCaseType))switchMode(currentCaseType);document.getElementById('welcomeScreen').style.display='none';document.getElementById('mainWorkarea').style.display='block';document.getElementById('clinicalInput').value=c.input;document.getElementById('charCount').textContent=c.input.length;document.getElementById('reportContent').innerHTML=c.output;applyReportTypo();caseImages=extractImages(c.output);renderImageThumbs();document.getElementById('outputSection').classList.add('active');document.getElementById('editHint').classList.add('active');const sh=getSheet(currentCaseType);document.getElementById('outputTypeBadge').textContent=sh?sh.name:currentCaseType;document.getElementById('btnSaveEdits').style.display='none';document.getElementById('inputToggle').style.display='flex';document.getElementById('inputBody').classList.add('collapsed');document.getElementById('inputToggle').classList.add('collapsed');document.getElementById('toggleLabel').textContent='Show Notes';document.getElementById('btnFollowup').style.display='inline-flex';document.getElementById('followupContainer').innerHTML='';document.getElementById('followupPromptArea').style.display='none';loadPersonalNote();renderSidebar();showChatToggle();loadChatForCase(currentCaseId);if(chatOpen)renderChatMessages();toast('Case loaded.');document.getElementById('outputSection').scrollIntoView({behavior:'smooth',block:'start'});if(window.innerWidth<=768)toggleSidebar();}catch(e){toast('Error: '+e.message,true);}}
async function regenCase(id){try{saveDraftIfNeeded();const c=await(await fetch(PROXY+'/history/'+id)).json();currentInput=c.input;currentCaseId=c.id;currentCaseType=c.type||'notes';if(S.sheets.find(s=>s.id===currentCaseType))switchMode(currentCaseType);document.getElementById('clinicalInput').value=c.input;document.getElementById('charCount').textContent=c.input.length;document.getElementById('inputBody').classList.remove('collapsed');document.getElementById('draftBanner').classList.remove('active');toast('Regenerating...');if(window.innerWidth<=768)toggleSidebar();await generateReport();}catch(e){toast('Error: '+e.message,true);}}
async function deleteCaseUI(id){showConfirm('Delete this case permanently?',async ok=>{if(!ok)return;try{await deleteCase(id);if(currentCaseId===id)doClearAll();toast('Deleted.');renderSidebar();}catch(e){toast('Error: '+e.message,true);}});}
