function startMiniDictation(ta,btn){if(btn.classList.contains('recording')){stopMiniDictation(btn);return;}if(!navigator.mediaDevices?.getUserMedia||typeof MediaRecorder==='undefined'){toast('Recording not supported in this browser.',true);return;}navigator.mediaDevices.getUserMedia({audio:true}).then(stream=>{btn._miniStream=stream;btn._miniChunks=[];btn._miniTa=ta;const mt=MediaRecorder.isTypeSupported('audio/webm;codecs=opus')?'audio/webm;codecs=opus':MediaRecorder.isTypeSupported('audio/mp4')?'audio/mp4':'audio/webm';btn._miniMimeType=mt;const mr=new MediaRecorder(stream,{mimeType:mt});mr.ondataavailable=e=>{if(e.data.size>0)btn._miniChunks.push(e.data);};mr.start(500);btn._miniMediaRecorder=mr;btn.classList.add('recording');btn.title='Stop dictation';if(btn._miniRecUI){btn._miniRecUI.classList.add('active');let secs=0;const timerEl=btn._miniRecUI.querySelector('.mn-mini-timer');btn._miniTimerInt=setInterval(()=>{secs++;const m=Math.floor(secs/60),s=secs%60;timerEl.textContent=m+':'+(s<10?'0':'')+s;},1000);}btn._silenceTimer=setTimeout(()=>{stopMiniDictation(btn);},120000);}).catch(()=>toast('Microphone access denied.',true));}
async function stopMiniDictation(btn){btn.classList.remove('recording');btn.title='Dictate';if(btn._miniRecUI){btn._miniRecUI.classList.remove('active');const timerEl=btn._miniRecUI.querySelector('.mn-mini-timer');if(timerEl)timerEl.textContent='0:00';}if(btn._miniTimerInt){clearInterval(btn._miniTimerInt);btn._miniTimerInt=null;}if(btn._silenceTimer){clearTimeout(btn._silenceTimer);btn._silenceTimer=null;}const mr=btn._miniMediaRecorder,stream=btn._miniStream,chunks=btn._miniChunks||[],mt=btn._miniMimeType||'audio/webm',ta=btn._miniTa||btn.nextElementSibling;btn._miniMediaRecorder=null;btn._miniStream=null;btn._miniChunks=[];if(mr&&mr.state!=='inactive'){await new Promise(r=>{mr.onstop=r;mr.stop();});}if(stream)stream.getTracks().forEach(t=>t.stop());if(!chunks.length){toast('No audio recorded.',true);return;}if(!ta)return;const oldPh=ta.placeholder;ta.placeholder='Transcribing...';ta.disabled=true;try{const blob=new Blob(chunks,{type:mt});if(blob.size<3000){toast('No speech detected.',true);return;}const fd=new FormData();fd.append('file',blob,'recording.'+getMimeExt(mt));const wResp=await fetch(PROXY+'/whisper',{method:'POST',body:fd});if(!wResp.ok)throw new Error('Whisper error '+wResp.status);const rawText=cleanWhisperText((await wResp.json()).text||'');if(!rawText){toast('No speech detected.',true);return;}ta.placeholder='Correcting for medical context...';const corrResp=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:getVoiceCorrectionPrompt(rawText)}]})});if(!corrResp.ok)throw new Error('Correction failed');const corrected=(await corrResp.json()).content.map(b=>b.text||'').join('').trim();if(!corrected||corrected==='DISCARD'){toast('No speech detected.',true);return;}const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+corrected):corrected;toast('Voice transcribed!');}catch(e){toast('Error: '+e.message,true);}finally{ta.placeholder=oldPh;ta.disabled=false;ta.focus();}}function stopVoiceRecorder(){voiceIsRecording=false;if(voiceTimerInterval){clearInterval(voiceTimerInterval);voiceTimerInterval=null;}document.getElementById('voiceRecorder').classList.remove('active');document.getElementById('btnMic').classList.remove('recording');document.getElementById('micStatus').textContent='';if(voiceAudioContext){voiceAudioContext.close();voiceAudioContext=null;}if(voiceMediaRecorder&&voiceMediaRecorder.state!=='inactive'){voiceMediaRecorder.onstop=()=>{voiceMediaRecorder=null;processVoiceAudio();};voiceMediaRecorder.stop();}else{processVoiceAudio();}if(voiceStream){voiceStream.getTracks().forEach(t=>t.stop());voiceStream=null;}}
async function processVoiceAudio(){if(!voiceAudioChunks.length){toast('No audio recorded. Try again.',true);return;}document.getElementById('voiceProcessing').classList.add('active');document.getElementById('voiceProcText').textContent='Transcribing with Whisper...';const chunks=[...voiceAudioChunks];voiceAudioChunks=[];try{const blob=new Blob(chunks,{type:voiceMimeType});if(blob.size<3000){toast('No speech detected. Try again.',true);return;}const fd=new FormData();fd.append('file',blob,'recording.'+getMimeExt(voiceMimeType));const wResp=await fetch(PROXY+'/whisper',{method:'POST',body:fd});if(!wResp.ok)throw new Error('Whisper error '+wResp.status);const rawText=cleanWhisperText((await wResp.json()).text||'');if(!rawText){toast('No speech detected. Try again.',true);return;}document.getElementById('voiceProcText').textContent='Correcting for medical context...';const correctResp=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:getVoiceCorrectionPrompt(rawText)}]})});if(!correctResp.ok)throw new Error('Correction failed');const correctedText=(await correctResp.json()).content.map(b=>b.text||'').join('').trim();if(!correctedText||correctedText==='DISCARD'){toast('No speech detected. Try again.',true);return;}const ta=document.getElementById('clinicalInput');const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+correctedText):correctedText;document.getElementById('charCount').textContent=ta.value.length;toast('Voice transcribed!');localStorage.setItem('draft_'+currentSheetId,ta.value);}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('voiceProcessing').classList.remove('active');}}function toggleExportMenu(){document.getElementById('exportWrap').classList.toggle('open');}
