function getVoiceCorrectionPrompt(rawText){const level=S&&S.voiceCorrection||'medium';const guard='\n\nIMPORTANT: If the text does not appear to be medical dictation (e.g. it looks like a random phrase, advertisement, video closing, or non-medical content), respond with only the single word: DISCARD\n\nDictated text:\n';const prompts={low:'You are a medical transcription editor. Lightly clean the following dictated text.\n\nRULES (LOW — stay very faithful to original):\n1. Fix only clear speech recognition errors (e.g. "high pertension"→"hypertension")\n2. Add minimal punctuation (periods at sentence ends)\n3. Do NOT rephrase, restructure, or reword anything\n4. Do NOT change word order or phrasing\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else',medium:'You are a medical transcription editor. Correct the following dictated text with moderate adjustments.\n\nRULES (MODERATE):\n1. Fix speech recognition errors and obvious medical terminology mistakes\n2. Fix clear grammar errors and add proper punctuation\n3. Keep the speaker\'s own words and phrasing — do NOT rephrase unnecessarily\n4. Maintain all clinical details exactly as stated\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else',high:'You are a medical transcription editor. Thoroughly correct the following dictated text.\n\nRULES (HIGH):\n1. Fix all grammar, punctuation, and sentence structure\n2. Correct all medical terminology\n3. Use professional medical language\n4. IMPORTANT: Keep all the same clinical information — do NOT add, remove, or change any medical facts\n5. Keep the same language as the input (English or Spanish)\n6. Return ONLY the corrected text, nothing else'};return(prompts[level]||prompts.medium)+guard+rawText;}
