function downloadNotepadDocx(){const outEl=document.getElementById('notepadOutputContent');const inEl=document.getElementById('notepadContent');const content=outEl.innerText.trim()||inEl.value;if(!content.trim()){toast('Nothing to export.',true);return;}const html=content.split('\n').map(l=>'<p>'+(esc(l)||'&nbsp;')+'</p>').join('');const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}p{margin:3pt 0}</style></head><body>'+html+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='Notepad.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}
