function buildImagePrompt(context){if(context)return'Context provided: '+context+'\n\nBased on this context, transcribe or describe the content of this image as accurately and completely as possible.\n\nFORMATTING RULES:\n- Preserve all values, units, dates, and data exactly as they appear.\n- Group related items together (e.g., all CBC values together, all BMP values together).\n- Use a single blank line between sections — no excessive spacing.\n- Use consistent label: value format (e.g., "WBC: 7.2 K/uL").\n- Do not add explanations or commentary — transcription only.\n\nReturn ONLY the organized transcription.';return'Look at this image carefully.\n\nIf it contains text, numbers, tables, lab values, prescriptions, or any readable content:\n- Transcribe faithfully and completely, preserving all values, units, dates, and structure.\n- Group related items together (e.g., all CBC values, all vitals, all medications).\n- Use single line breaks within a group, one blank line between groups.\n- Use consistent label: value format where applicable.\n- Avoid excessive blank lines or spacing.\n- Do NOT add explanations or commentary.\n\nIf it appears to be a medical imaging study (X-ray, CT, MRI, ultrasound, echocardiogram, pathology slide, angiography, etc.) without readable text: respond with exactly the word: IMAGING_DETECTED\n\nReturn ONLY the organized transcription or IMAGING_DETECTED.';}
async function callVisionAPI(dataUrl,promptText){const match=dataUrl.match(/^data:([^;]+);base64,(.+)$/);if(!match)throw new Error('Invalid image');const mediaType=match[1];const b64=match[2];const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:4096,messages:[{role:'user',content:[{type:'image',source:{type:'base64',media_type:mediaType,data:b64}},{type:'text',text:promptText}]}]})});if(!r.ok)throw new Error('API error '+r.status);const d=await r.json();return d.content.map(b=>b.text||'').join('').trim();}
async function readImageContent(){if(!readerImageDataUrl){toast('Upload an image first.',true);return;}const context=(document.getElementById('readerContextArea')?.value||'').trim();document.getElementById('readerLoader').style.display='block';document.getElementById('readerResultArea').style.display='none';try{const text=await callVisionAPI(readerImageDataUrl,buildImagePrompt(context));if(text==='IMAGING_DETECTED'){document.getElementById('imagingContextModal').classList.add('open');window._imagingTarget='reader';}else{document.getElementById('readerResult').innerText=text;document.getElementById('readerResultArea').style.display='block';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('readerLoader').style.display='none';}}
function clearImageReader(){readerImageDataUrl=null;document.getElementById('readerFileInput').value='';document.getElementById('readerPreviewArea').style.display='none';document.getElementById('readerResultArea').style.display='none';const ca=document.getElementById('readerContextArea');if(ca){ca.value='';ca.style.display='none';}const ct=document.getElementById('readerContextToggle');if(ct)ct.textContent='+ Add context (optional)';}
function toggleReaderContext(){const ca=document.getElementById('readerContextArea');const ct=document.getElementById('readerContextToggle');if(!ca)return;const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
let inlineReaderDataUrl=null;
function handleInlineReaderFile(file){if(!file)return;const reader=new FileReader();reader.onload=e=>{inlineReaderDataUrl=e.target.result;document.getElementById('inlineReaderImg').src=inlineReaderDataUrl;document.getElementById('inlineReader').style.display='block';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnAddToNotes').style.display='none';document.getElementById('btnTranscribeInline').style.display='';document.getElementById('inlineReaderContext').value='';document.getElementById('inlineReaderContext').style.display='none';document.getElementById('inlineContextToggle').textContent='+ Add context (optional)';document.getElementById('inlineReaderInput').value='';};reader.readAsDataURL(file);}
function toggleInlineContext(){const ca=document.getElementById('inlineReaderContext');const ct=document.getElementById('inlineContextToggle');const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
async function transcribeInlineImage(){if(!inlineReaderDataUrl){toast('No image loaded.',true);return;}const context=(document.getElementById('inlineReaderContext').value||'').trim();document.getElementById('inlineReaderLoader').style.display='block';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnTranscribeInline').disabled=true;try{const text=await callVisionAPI(inlineReaderDataUrl,buildImagePrompt(context));if(text==='IMAGING_DETECTED'){document.getElementById('imagingContextModal').classList.add('open');window._imagingTarget='inline';}else{document.getElementById('inlineReaderResult').value=text;document.getElementById('inlineReaderResultArea').style.display='block';document.getElementById('btnAddToNotes').style.display='';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('inlineReaderLoader').style.display='none';document.getElementById('btnTranscribeInline').disabled=false;}}
function appendInlineTranscription(){const text=document.getElementById('inlineReaderResult').value.trim();if(!text){toast('No transcription to add.',true);return;}const ta=document.getElementById('clinicalInput');const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+text):text;document.getElementById('charCount').textContent=ta.value.length;if(!reportGenerated)localStorage.setItem('draft_'+currentSheetId,ta.value);toast('Added to notes!');clearInlineReader();}
function clearInlineReader(){inlineReaderDataUrl=null;document.getElementById('inlineReader').style.display='none';document.getElementById('inlineReaderInput').value='';document.getElementById('inlineReaderResultArea').style.display='none';document.getElementById('btnAddToNotes').style.display='none';}
function closeImagingModal(){document.getElementById('imagingContextModal').classList.remove('open');window._imagingTarget=null;}
async function interpretWithImagingContext(){const context=document.getElementById('imagingContextInput').value.trim();if(!context){toast('Please provide context first.',true);return;}closeImagingModal();const target=window._imagingTarget;if(target==='inline'){document.getElementById('inlineReaderContext').value=context;document.getElementById('inlineReaderContext').style.display='block';document.getElementById('inlineContextToggle').textContent='- Hide context';await transcribeInlineImage();}else if(target&&target.startsWith('mn_')){const mnid=target.slice(3);document.getElementById('mnInlineReaderContext_'+mnid).value=context;document.getElementById('mnInlineReaderContext_'+mnid).style.display='block';document.getElementById('mnInlineCtxToggle_'+mnid).textContent='- Hide context';await transcribeMNInlineImage(mnid);}else if(target&&target.startsWith('mnprompt_')){const key=target.slice(9);const taId=window._imagingTargetTaId;document.getElementById('mnPromptReaderCtx_'+key).value=context;document.getElementById('mnPromptReaderCtx_'+key).style.display='block';document.getElementById('mnPromptCtxToggle_'+key).textContent='- Hide context';await transcribeMNPromptImage(key,taId);}else{document.getElementById('readerContextArea').value=context;document.getElementById('readerContextArea').style.display='block';document.getElementById('readerContextToggle').textContent='- Hide context';await readImageContent();}}
function copyReaderResult(){const t=document.getElementById('readerResult').innerText;navigator.clipboard.writeText(t).then(()=>toast('Copied!')).catch(()=>toast('Copy failed.',true));}
function toggleReaderExport(){document.getElementById('readerExportWrap').classList.toggle('open');}
function closeReaderExport(){document.getElementById('readerExportWrap')?.classList.remove('open');}
async function downloadReaderPDF(){const el=document.getElementById('readerResult');if(!el.innerText.trim()){toast('Nothing to export.',true);return;}toast('Preparing PDF...');try{const canvas=await html2canvas(el,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Image_Transcription.pdf');toast('PDF ready.');}catch{toast('PDF error.',true);}}
function downloadReaderDocx(){const text=document.getElementById('readerResult').innerText;if(!text.trim()){toast('Nothing to export.',true);return;}const html=text.split('\n').map(l=>'<p>'+(esc(l)||'&nbsp;')+'</p>').join('');const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}p{margin:3pt 0}</style></head><body>'+html+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='Image_Transcription.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}
async function loadImageBank(){const container=document.getElementById('imageBankGrid');container.innerHTML='<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);padding:40px">Loading...</div>';try{const cases=await loadHistory();const allImages=[];for(const c of cases){const imgs=extractImages(c.output||'');imgs.forEach(img=>allImages.push({...img,caseName:c.title||'Untitled',caseId:c.id}));}caseImages.forEach(img=>{if(!allImages.find(i=>i.dataUrl===img.dataUrl))allImages.push({...img,caseName:'Current session',caseId:null});});if(!allImages.length){container.innerHTML='<div style="grid-column:1/-1;text-align:center;color:var(--text-muted);padding:40px;border:2px dashed var(--border);border-radius:var(--radius)">No images found. Add images to cases to see them here.</div>';return;}container.innerHTML=allImages.map(img=>`<div class="mn-bank-item" onclick="openImgPreview('${img.dataUrl}')"><img src="${img.dataUrl}" alt="${esc(img.name)}"><div class="mn-bank-item-label">${esc(img.caseName)}</div></div>`).join('');}catch(e){container.innerHTML='<div style="grid-column:1/-1;color:var(--danger);padding:20px">Error loading images.</div>';}}
function toast(msg,err){const t=document.getElementById('toast');t.textContent=msg;t.className='mn-toast show'+(err?' error':'');setTimeout(()=>t.className='mn-toast',3000);}
function toggleInput(){const b=document.getElementById('inputBody'),tg=document.getElementById('inputToggle');const c=b.classList.toggle('collapsed');tg.classList.toggle('collapsed',c);document.getElementById('toggleLabel').textContent=c?'Show Notes':'Hide Notes';}
function toggleEditPanel(){const p=document.getElementById('editPanel');p.classList.toggle('active');if(p.classList.contains('active'))document.getElementById('editInstructions').focus();}

const EDIT_PROMPT='You are a medical documentation assistant.\nYou previously generated this report:\n\n{{CURRENT_REPORT}}\n\nChanges requested:\n\n{{EDIT_INSTRUCTIONS}}\n\nApply ONLY the requested changes. Keep everything else. Return FULL report as clean HTML.';

async function generateReport(){const text=document.getElementById('clinicalInput').value.trim();if(!text){toast('Enter notes first.',true);return;}if(text.length<30){toast('Too short.',true);return;}const saveType=currentSheetId;currentInput=text;savedDraft='';currentCaseType=saveType;localStorage.removeItem('draft_'+currentSheetId);document.getElementById('draftBanner').classList.remove('active');document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Structuring — please wait...';document.getElementById('outputSection').classList.remove('active');document.getElementById('btnGenerate').disabled=true;try{const html=await callAPI(getActivePrompt().replace('{{USER_TEXT}}',text));const stamp='<div class="mn-doctor-stamp">'+getDoctorStampHTML()+'</div>';structuredText=html+stamp;reportGenerated=true;hasUnsavedEdits=false;document.getElementById('reportContent').innerHTML=structuredText;applyReportTypo();if(caseImages.length)syncImagesInReport();document.getElementById('outputSection').classList.add('active');document.getElementById('editHint').classList.add('active');const sh=curSheet();document.getElementById('outputTypeBadge').textContent=sh.name;document.getElementById('btnSaveEdits').style.display='none';document.getElementById('inputToggle').style.display='flex';document.getElementById('inputBody').classList.add('collapsed');document.getElementById('inputToggle').classList.add('collapsed');document.getElementById('toggleLabel').textContent='Show Notes';document.getElementById('btnFollowup').style.display='inline-flex';const title=extractTitle(html);const id=currentCaseId||('case_'+Date.now());currentCaseId=id;await saveCase(id,title,text,getLiveReportHTML(),saveType);renderSidebar();showChatToggle();loadChatForCase(currentCaseId);if(chatOpen)renderChatMessages();toast('Report generated.');document.getElementById('outputSection').scrollIntoView({behavior:'smooth',block:'start'});}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');document.getElementById('btnGenerate').disabled=false;}}
async function applyEdit(){const ins=document.getElementById('editInstructions').value.trim();if(!ins){toast('Describe changes.',true);return;}document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Applying changes — please wait...';document.getElementById('btnApplyEdit').disabled=true;document.getElementById('btnApplyEdit').textContent='Processing...';try{const html=await callAPI(EDIT_PROMPT.replace('{{CURRENT_REPORT}}',getLiveReportHTML()).replace('{{EDIT_INSTRUCTIONS}}',ins));structuredText=html;document.getElementById('reportContent').innerHTML=html;applyReportTypo();if(caseImages.length)syncImagesInReport();document.getElementById('editPanel').classList.remove('active');document.getElementById('editInstructions').value='';hasUnsavedEdits=false;if(currentCaseId){await saveCase(currentCaseId,extractTitle(html),currentInput,html,currentCaseType);renderSidebar();}toast('Applied.');}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');document.getElementById('btnApplyEdit').disabled=false;document.getElementById('btnApplyEdit').textContent='Apply';}}
async function copyToClipboard(){const el=document.getElementById('reportContent'),h=el.innerHTML,pt=el.innerText;try{if(navigator.clipboard&&window.ClipboardItem){await navigator.clipboard.write([new ClipboardItem({'text/html':new Blob([h],{type:'text/html'}),'text/plain':new Blob([pt],{type:'text/plain'})})]);toast('Copied!');}else{await navigator.clipboard.writeText(pt);toast('Copied.');}}catch{toast('Copy failed.',true);}}
async function downloadPDF(){toast('Preparing PDF...');try{const canvas=await html2canvas(document.getElementById('reportContent'),{scale:2,useCORS:true,backgroundColor:document.documentElement.classList.contains('dark')?'#1a1d28':'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20,pH=pdf.internal.pageSize.getHeight()-20,ih=canvas.height*pw/canvas.width;if(ih<=pH)pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);else{let sY=0;while(sY<canvas.height){const sH=Math.min(canvas.height-sY,canvas.width*pH/pw);const sl=document.createElement('canvas');sl.width=canvas.width;sl.height=sH;sl.getContext('2d').drawImage(canvas,0,sY,canvas.width,sH,0,0,canvas.width,sH);if(sY>0)pdf.addPage();pdf.addImage(sl.toDataURL('image/png'),'PNG',10,10,pw,sH*pw/canvas.width);sY+=sH;}}pdf.save(curSheet().name.replace(/\s/g,'_')+'_Report.pdf');toast('PDF ready.');}catch(e){toast('PDF error.',true);}}
function downloadDOCX(){try{const h=document.getElementById('reportContent').innerHTML;const sh=curSheet();const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}h2{font-size:13pt;font-weight:bold;color:'+sh.color+';border-bottom:1px solid #ddd;padding-bottom:4pt}p{margin:3pt 0}strong{font-weight:bold}</style></head><body><div style="text-align:center;font-size:15pt;font-weight:bold;color:'+sh.color+';margin-bottom:12pt">'+esc(sh.name).toUpperCase()+'</div><hr style="border:1px solid #ddd;margin-bottom:16pt">'+h+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=sh.name.replace(/\s/g,'_')+'_Report.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}catch{toast('Word error.',true);}}
function clearAll(){const txt=document.getElementById('clinicalInput').value;const rep=document.getElementById('reportContent').innerText||'';if(txt.length>50||rep.length>50){showConfirm('You have content in the editor. <strong>Clear everything?</strong> This cannot be undone.',ok=>{if(ok)doClearAll();});}else{doClearAll();}}
function doClearAll(){document.getElementById('clinicalInput').value='';document.getElementById('charCount').textContent='0';document.getElementById('reportContent').innerHTML='';document.getElementById('outputSection').classList.remove('active');document.getElementById('editHint').classList.remove('active');document.getElementById('editPanel').classList.remove('active');document.getElementById('btnSaveEdits').style.display='none';document.getElementById('saveIndicator').classList.remove('active');document.getElementById('draftBanner').classList.remove('active');document.getElementById('btnFollowup').style.display='none';document.getElementById('followupContainer').innerHTML='';document.getElementById('followupPromptArea').style.display='none';document.getElementById('medicalNotesContainer').innerHTML='';document.getElementById('medicalNotesPromptArea').style.display='none';savedDraft='';structuredText='';reportGenerated=false;currentCaseId=null;currentInput='';hasUnsavedEdits=false;followupCount=0;medicalNotesCount=0;clearCaseImages();document.getElementById('inputToggle').style.display='none';document.getElementById('inputBody').classList.remove('collapsed');if(chatOpen)minimizeChat();toast('Cleared.');}

/* ═══ CASE ASSISTANT CHAT ═══ */
let chatOpen=false,caseChats={},chatWidth=380;
function expandChat(){chatOpen=true;const p=document.getElementById('chatPanel');p.classList.remove('peeking');p.classList.add('expanded');if(window.innerWidth>768)p.style.width=chatWidth+'px';else p.style.width='100%';document.getElementById('mainArea').classList.add('chat-expanded');renderChatMessages();setTimeout(()=>document.getElementById('chatInput').focus(),300);}
function minimizeChat(){chatOpen=false;const p=document.getElementById('chatPanel');p.classList.remove('expanded');p.classList.add('peeking');p.style.width='';document.getElementById('mainArea').classList.remove('chat-expanded');}
function toggleMobileChat(){if(chatOpen){minimizeChat();}else{expandChat();}}
function toggleChat(){if(chatOpen)minimizeChat();else expandChat();}
function showChatToggle(){}
/* Resize drag */
(function(){const handle=document.getElementById('chatResize');if(!handle)return;let dragging=false,startX,startW;handle.addEventListener('mousedown',e=>{dragging=true;startX=e.clientX;startW=document.getElementById('chatPanel').offsetWidth;document.body.style.cursor='col-resize';document.body.style.userSelect='none';e.preventDefault();});document.addEventListener('mousemove',e=>{if(!dragging)return;const diff=startX-e.clientX;const nw=Math.min(600,Math.max(260,startW+diff));document.getElementById('chatPanel').style.width=nw+'px';chatWidth=nw;});document.addEventListener('mouseup',()=>{if(dragging){dragging=false;document.body.style.cursor='';document.body.style.userSelect='';}});})();
function getCaseChat(){if(!currentCaseId)return[];if(!caseChats[currentCaseId])caseChats[currentCaseId]=[];return caseChats[currentCaseId];}
function copyChatMsg(idx){const msgs=getCaseChat();const m=msgs[idx];if(!m)return;navigator.clipboard.writeText(m.text).then(()=>toast('Copied.')).catch(()=>toast('Copy failed.',true));}
function renderChatMessages(){const el=document.getElementById('chatMessages');const msgs=getCaseChat();if(!msgs.length||!currentCaseId){el.innerHTML='<div class="mn-chat-empty"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg><br>'+(currentCaseId?'Ask me anything about this case.':'Generate a report first.')+'</div>';return;}
el.innerHTML=msgs.map((m,i)=>{if(m.role==='user')return'<div class="mn-chat-msg user">'+esc(m.text)+'</div>';
return'<div class="mn-chat-msg ai">'+(m.html||esc(m.text))+'<button class="mn-chat-copy" onclick="copyChatMsg('+i+')" title="Copy"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg> Copy</button></div>';}).join('');el.scrollTop=el.scrollHeight;}
async function sendChat(){const inp=document.getElementById('chatInput');const text=inp.value.trim();if(!text)return;if(!currentCaseId||!reportGenerated){toast('Generate a report first.',true);return;}
if(!chatOpen)expandChat();
const msgs=getCaseChat();msgs.push({role:'user',text});inp.value='';renderChatMessages();
const el=document.getElementById('chatMessages');el.innerHTML+='<div class="mn-chat-msg ai typing">Thinking...</div>';el.scrollTop=el.scrollHeight;
document.getElementById('chatSendBtn').disabled=true;
try{const reportText=document.getElementById('reportContent').innerText||'';
const history=msgs.filter(m=>m.role).slice(-10).map(m=>({role:m.role==='user'?'user':'assistant',content:m.text}));
const sysContent='You are a medical case assistant. Answer questions about the case based on the report below. Be helpful, precise, professional medical language. Do NOT modify the report. Only provide information, analysis, recommendations.\n\nREPORT:\n'+reportText;
const apiMsgs=[{role:'user',content:sysContent},...history];
const r=await fetch(PROXY,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:2048,messages:apiMsgs})});
if(!r.ok)throw new Error('API error '+r.status);
const d=await r.json();let reply=d.content.map(b=>b.text||'').join('');
const html=reply.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n- /g,'\n• ').replace(/\n/g,'<br>');
msgs.push({role:'ai',text:reply,html});
saveChatForCase();renderChatMessages();
}catch(e){msgs.push({role:'ai',text:'Error: '+e.message,html:'Error: '+esc(e.message)});renderChatMessages();}
document.getElementById('chatSendBtn').disabled=false;}
function saveChatForCase(){if(!currentCaseId)return;try{const all=JSON.parse(localStorage.getItem('mn_chats')||'{}');all[currentCaseId]=getCaseChat();localStorage.setItem('mn_chats',JSON.stringify(all));}catch{}}
function loadChatForCase(caseId){try{const all=JSON.parse(localStorage.getItem('mn_chats')||'{}');caseChats[caseId]=all[caseId]||[];}catch{caseChats[caseId]=[];}}

/* ═══ READ ALOUD (OpenAI TTS) ═══ */
let ttsAudio=null,ttsReading=false;
const TTS_ICON='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:17px;height:17px"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 010 7.07"/><path d="M19.07 4.93a10 10 0 010 14.14"/></svg>';
const TTS_STOP='<svg viewBox="0 0 24 24" fill="currentColor" style="width:14px;height:14px"><rect x="6" y="6" width="12" height="12" rx="2"/></svg>';
const TTS_SPIN='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="width:14px;height:14px;animation:mn-spin .8s linear infinite;display:block"><path d="M21 12a9 9 0 11-6.219-8.56"/></svg>';
function ttsSetState(btn,statusEl,state){
  if(state==='idle'){btn.innerHTML=TTS_ICON;btn.classList.remove('mn-btn-danger');btn.classList.add('mn-btn-outline');btn.style.opacity='.7';btn.disabled=false;if(statusEl){statusEl.textContent='';statusEl.style.display='none';}}
  else if(state==='loading'){btn.innerHTML=TTS_SPIN;btn.classList.remove('mn-btn-danger');btn.classList.add('mn-btn-outline');btn.style.opacity='1';btn.disabled=false;if(statusEl){statusEl.textContent='Processing...';statusEl.style.display='inline';}}
  else if(state==='playing'){btn.innerHTML=TTS_STOP;btn.classList.remove('mn-btn-outline');btn.classList.add('mn-btn-danger');btn.style.opacity='1';btn.disabled=false;if(statusEl){statusEl.textContent='Reading...';statusEl.style.display='inline';}}
}
async function toggleReadAloud(){
  const btn=document.getElementById('btnReadAloud');
  const statusEl=document.getElementById('ttsStatusMain');
  if(ttsReading){if(ttsAudio){ttsAudio.pause();ttsAudio=null;}ttsReading=false;ttsSetState(btn,statusEl,'idle');return;}
  const text=document.getElementById('reportContent').innerText||'';
  if(!text.trim()){toast('No report to read.',true);return;}
  ttsReading=true;ttsSetState(btn,statusEl,'loading');
  try{
    const res=await fetch(PROXY+'/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({input:text.slice(0,4096),voice:'alloy',model:'tts-1'})});
    if(!res.ok)throw new Error();
    const url=URL.createObjectURL(await res.blob());
    ttsAudio=new Audio(url);
    ttsSetState(btn,statusEl,'playing');
    const reset=()=>{URL.revokeObjectURL(url);ttsReading=false;ttsAudio=null;ttsSetState(btn,statusEl,'idle');};
    ttsAudio.onended=reset;ttsAudio.onerror=reset;ttsAudio.play();
  }catch(e){ttsReading=false;ttsAudio=null;ttsSetState(btn,statusEl,'idle');toast('Read Aloud unavailable.',true);}
}

/* ═══ DRAFT AUTO-SAVE ═══ */
function autoSaveDraft(){const txt=document.getElementById('clinicalInput').value.trim();if(txt&&!reportGenerated){localStorage.setItem('draft_'+currentSheetId,txt);}else{localStorage.removeItem('draft_'+currentSheetId);}}
document.getElementById('clinicalInput').addEventListener('input',function(){document.getElementById('charCount').textContent=this.value.length;if(!reportGenerated)localStorage.setItem('draft_'+currentSheetId,this.value);});

/* ═══ WELCOME SCREEN ═══ */
function renderWelcome(){const g=document.getElementById('welcomeGrid');g.innerHTML=S.sheets.map(sh=>'<div class="mn-welcome-card" onclick="startFromWelcome(\''+sh.id+'\')"><div class="wc-dot" style="background:'+sh.color+'"></div><div class="wc-name">'+esc(sh.name)+'</div><div class="wc-desc">Start a new report</div></div>').join('');renderRecentCases();}
async function renderRecentCases(){const container=document.getElementById('recentCasesList');if(!container)return;const cases=await loadHistory();const recent=cases.slice().sort((a,b)=>(b.timestamp||0)-(a.timestamp||0)).slice(0,9);const search=(document.getElementById('recentSearch')?.value||'').trim().toLowerCase();let filtered=recent;if(search)filtered=recent.filter(c=>{const hay=((c.title||'')+' '+(c.input||'')+' '+(c.output||'')+' '+(c.type||'')).toLowerCase();return hay.includes(search);});if(!filtered.length){container.innerHTML='<div class="mn-recent-empty">'+(recent.length?'No matching cases.':'No cases yet. Start a new report above.')+'</div>';return;}const bookmarks=getBookmarks();container.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp),ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric'}),ts=d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});const type=c.type||'notes';const sh=getSheet(type);const color=sh?sh.color:'#888';const label=sh?sh.name:type;const meta=extractMeta(c.output||'');const patientName=(meta.name&&meta.name!=='Not provided')?meta.name:(c.title||'Untitled');const age=(meta.age&&meta.age!=='Not provided')?meta.age:'';const complaint=(meta.complaint&&meta.complaint!=='Not provided')?meta.complaint:'';const isBookmarked=bookmarks.includes(c.id);const starClass=isBookmarked?'mn-recent-star active':'mn-recent-star';const starTitle=isBookmarked?'Remove bookmark':'Save bookmark';return '<div class="mn-recent-card" onclick="loadCase(\''+c.id+'\')" style="border-top:3px solid '+color+'"><div class="mn-recent-card-top"><span class="mn-recent-badge" style="background:'+color+'22;color:'+color+'">'+esc(label)+'</span><button class="'+starClass+'" onclick="event.stopPropagation();toggleRecentBookmark(\''+c.id+'\')" title="'+starTitle+'">&#9733;</button></div><div class="mn-recent-card-name">'+esc(patientName)+'</div>'+(age?'<div class="mn-recent-card-age">Age: '+esc(age)+'</div>':'')+(complaint?'<div class="mn-recent-card-cc"><span class="mn-recent-cc-label">CC</span> '+esc(complaint)+'</div>':'')+'<div class="mn-recent-card-date">'+ds+' · '+ts+'</div></div>';}).join('');}
function toggleRecentBookmark(id){toggleBookmarkCase(id);renderRecentCases();}function filterRecentCases(){renderRecentCases();}function startFromWelcome(sheetId){switchMode(sheetId);newCase();}
function showWelcome(){hideSpecialPanels();document.querySelectorAll('#tabNotepad,#tabImageReader,#tabImageBank').forEach(b=>b.classList.remove('active'));document.getElementById('welcomeScreen').style.display='block';document.getElementById('mainWorkarea').style.display='none';renderRecentCases();}
/* ═══ PERSONAL NOTES ═══ */
function savePersonalNote(){if(!currentCaseId)return;const t=document.getElementById('personalNotes').value;try{const all=JSON.parse(localStorage.getItem('mn_pnotes')||'{}');all[currentCaseId]=t;localStorage.setItem('mn_pnotes',JSON.stringify(all));}catch{}}
function loadPersonalNote(){const el=document.getElementById('personalNotes');if(!currentCaseId){el.value='';return;}try{const all=JSON.parse(localStorage.getItem('mn_pnotes')||'{}');el.value=all[currentCaseId]||'';}catch{el.value='';}}

/* ═══ BOOKMARKS ═══ */
function getBookmarks(){try{return JSON.parse(localStorage.getItem('mn_bookmarks')||'[]');}catch{return[];}}
function setBookmarks(b){localStorage.setItem('mn_bookmarks',JSON.stringify(b));}
function toggleBookmarkCase(id){let b=getBookmarks();if(b.includes(id))b=b.filter(x=>x!==id);else b.push(id);setBookmarks(b);renderBookmarks();renderFullHistory();}
function toggleBookmarks(){const l=document.getElementById('bookmarksList');l.classList.toggle('open');if(l.classList.contains('open'))renderBookmarks();}
async function renderBookmarks(){const bm=getBookmarks();document.getElementById('bookmarkCount').textContent='('+bm.length+')';const l=document.getElementById('bookmarksList');if(!bm.length){l.innerHTML='<div class="mn-sidebar-empty" style="padding:12px;font-size:.72rem">No saved cases.</div>';return;}
const cases=await loadHistory();const saved=cases.filter(c=>bm.includes(c.id));l.innerHTML=saved.map(c=>{const sh=getSheet(c.type||'notes');const color=sh?sh.color:'#888';return'<div class="mn-sidebar-item" onclick="loadCase(\''+c.id+'\')"><div class="mn-sidebar-item-title"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+'">&#9733;</span>'+esc(c.title||'Untitled')+'</div></div>';}).join('');}

/* ═══ FULL HISTORY MODAL ═══ */
function openFullHistory(){updateFHFilters();renderFullHistory();document.getElementById('fullHistOverlay').classList.add('active');}
function closeFullHistory(){document.getElementById('fullHistOverlay').classList.remove('active');}
function updateFHFilters(){const sel=document.getElementById('fhFilterType');sel.innerHTML='<option value="all">All Types</option>'+S.sheets.map(sh=>'<option value="'+sh.id+'">'+esc(sh.name)+'</option>').join('');}
async function renderFullHistory(){const cases=await loadHistory();const fType=document.getElementById('fhFilterType').value;const fSearch=(document.getElementById('fhSearch').value||'').toLowerCase();const fFrom=document.getElementById('fhFrom').value;const fTo=document.getElementById('fhTo').value;const bm=getBookmarks();
let filtered=cases;if(fType&&fType!=='all')filtered=filtered.filter(c=>(c.type||'notes')===fType);if(fFrom)filtered=filtered.filter(c=>c.timestamp>=new Date(fFrom).getTime());if(fTo)filtered=filtered.filter(c=>c.timestamp<new Date(fTo).getTime()+86400000);if(fSearch)filtered=filtered.filter(c=>((c.title||'')+(c.input||'')).toLowerCase().includes(fSearch));
const l=document.getElementById('fhList');if(!filtered.length){l.innerHTML='<div style="text-align:center;padding:40px;color:var(--text-muted)">No cases found.</div>';return;}
l.innerHTML=filtered.map(c=>{const d=new Date(c.timestamp);const ds=d.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric',hour:'2-digit',minute:'2-digit'});const sh=getSheet(c.type||'notes');const color=sh?sh.color:'#888';const isBm=bm.includes(c.id);
return'<div class="mn-fullhist-item" onclick="loadCase(\''+c.id+'\');closeFullHistory()"><span class="mn-type-badge" style="background:'+color+'22;color:'+color+';flex-shrink:0">'+(sh?sh.name.substring(0,4).toUpperCase():'NOTE')+'</span><div class="mn-fullhist-item-info"><div class="mn-fullhist-item-title">'+esc(c.title||'Untitled')+'</div><div class="mn-fullhist-item-date">'+ds+'</div></div><div class="mn-fullhist-item-btns" onclick="event.stopPropagation()"><button class="mn-fh-bookmark'+(isBm?' saved':'')+'" onclick="toggleBookmarkCase(\''+c.id+'\')" title="'+(isBm?'Remove bookmark':'Bookmark')+'">&#9733;</button><button style="background:var(--danger-light);color:var(--danger)" onclick="deleteCaseUI(\''+c.id+'\');renderFullHistory()">Del</button></div></div>';}).join('');}

/* ═══ GENERATE MENU ═══ */
let generateForSheetId=null;
function toggleGenerateMenu(){
  const wrap=document.getElementById('generateWrap');if(!wrap)return;
  const open=wrap.classList.contains('open');
  closeExportMenu();closeGenerateMenu();
  if(!open){
    const menu=document.getElementById('generateMenu');
    let html='';
    S.sheets.forEach(sh=>{html+=`<button onclick="showGenerateForSheet('${sh.id}');closeGenerateMenu()"><span style="width:8px;height:8px;border-radius:50%;background:${sh.color};display:inline-block;flex-shrink:0;margin-right:4px"></span>${esc(sh.name)}</button>`;});
    html+='<hr style="margin:4px 0;border:none;border-top:1px solid var(--border)">';
    html+='<button onclick="generateForSheetId=null;showFollowupPrompt();closeGenerateMenu()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:12px;height:12px"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Follow-up Report</button>';
    menu.innerHTML=html;wrap.classList.add('open');
  }
}
function closeGenerateMenu(){document.getElementById('generateWrap')?.classList.remove('open');}
function toggleEditHint(e){e.stopPropagation();const p=document.getElementById('editHintPopover');p.style.display=p.style.display==='none'?'block':'none';}
function toggleFollowupHint(e){e.stopPropagation();const p=document.getElementById('followupHintPopover');p.style.display=p.style.display==='none'?'block':'none';}
document.addEventListener('click',()=>{['editHintPopover','followupHintPopover'].forEach(id=>{const p=document.getElementById(id);if(p)p.style.display='none';});});
function showGenerateForSheet(sheetId){
  closeGenerateMenu();
  if(sheetId==='notes'){showMedicalNotesPrompt();return;}
  generateForSheetId=sheetId;
  const sh=getSheet(sheetId);
  const lbl=document.getElementById('followupLabel');const ta=document.getElementById('followupInstructions');
  if(lbl)lbl.textContent=(sh?sh.name:'Report')+' — New Information';
  if(ta)ta.placeholder='Enter new clinical information to generate '+(sh?sh.name:'this report')+'...';
  showFollowupPrompt();
}

/* ═══ FOLLOW-UP REPORTS ═══ */
let followupCount=0;
function showFollowupPrompt(){document.getElementById('followupPromptArea').style.display='block';attachMiniMic('followupInstructions');document.getElementById('followupInstructions').focus();document.getElementById('followupPromptArea').scrollIntoView({behavior:'smooth'});}
function hideFollowupPrompt(){
  document.getElementById('followupPromptArea').style.display='none';
  generateForSheetId=null;
  const lbl=document.getElementById('followupLabel');const ta=document.getElementById('followupInstructions');
  if(lbl)lbl.textContent='Follow-up Report Instructions';
  if(ta)ta.placeholder='Describe what this follow-up report should focus on...';
}
async function generateFollowup(){const instructions=document.getElementById('followupInstructions').value.trim();if(!instructions){toast('Describe what this should contain.',true);return;}
const sheetId=generateForSheetId;generateForSheetId=null;
const sh=sheetId?getSheet(sheetId):null;
const prevReport=document.getElementById('reportContent').innerText||'';
document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Generating — please wait...';
const lbl=document.getElementById('followupLabel');const ta=document.getElementById('followupInstructions');
if(lbl)lbl.textContent='Follow-up Report Instructions';if(ta)ta.placeholder='Describe what this follow-up report should focus on...';
try{
  let prompt;
  if(sheetId){
    prompt=buildPrompt(sheetId).replace('{{USER_TEXT}}','PREVIOUS REPORT CONTEXT:\n'+prevReport+'\n\nNEW CLINICAL INFORMATION:\n'+instructions);
  }else{
    prompt='You are a medical documentation assistant.\nBased on the PREVIOUS REPORT below, generate a NEW follow-up report as requested.\n\nPREVIOUS REPORT:\n'+prevReport+'\n\nUSER REQUEST:\n'+instructions+'\n\nRULES:\n- Generate ONLY the requested content as a NEW standalone report section.\n- Use clean HTML: <h2> for titles, <p> for content, <strong> for labels.\n- Professional medical language.\n- Do NOT repeat the entire previous report, only the new requested content.\n\nOUTPUT: Return the follow-up report as HTML.';
  }
  const html=await callAPI(prompt);followupCount++;
  const fid='followup_'+followupCount;
  const cardLabel=sh?sh.name+' #'+followupCount:'Follow-up Report #'+followupCount;
  const container=document.getElementById('followupContainer');
  container.insertAdjacentHTML('beforeend','<div class="mn-followup-section" id="'+fid+'"><div class="mn-output-label">'+esc(cardLabel)+' <span class="mn-badge mn-badge-ready">Ready</span></div><div class="mn-card"><div class="mn-report" contenteditable="true" spellcheck="true">'+html+'</div><div class="mn-actions" style="margin-top:12px;border-top:1px solid var(--border);padding-top:10px"><button class="mn-btn mn-btn-outline" onclick="copyFollowup(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">Copy</button><button class="mn-btn mn-btn-outline" onclick="downloadFollowupPDF(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">PDF</button><button class="mn-btn mn-btn-outline" onclick="readFollowup(\''+fid+'\')" style="font-size:.78rem;padding:7px 14px">Read</button></div></div></div>');
  document.getElementById('followupPromptArea').style.display='none';document.getElementById('followupInstructions').value='';
  document.getElementById(fid).scrollIntoView({behavior:'smooth'});toast((sh?sh.name:'Follow-up')+' generated.');
}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');}}
function copyFollowup(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;navigator.clipboard.writeText(el.innerText).then(()=>toast('Copied.')).catch(()=>toast('Copy failed.',true));}
async function downloadFollowupPDF(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;toast('Preparing PDF...');try{const canvas=await html2canvas(el,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Followup_Report.pdf');toast('PDF ready.');}catch{toast('PDF error.',true);}}
async function readFollowup(fid){const el=document.querySelector('#'+fid+' .mn-report');if(!el)return;try{const res=await fetch(PROXY+'/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({input:el.innerText.slice(0,4096),voice:'alloy',model:'tts-1'})});if(!res.ok)throw new Error();const url=URL.createObjectURL(await res.blob());const a=new Audio(url);a.onended=()=>URL.revokeObjectURL(url);a.play();}catch{toast('Read Aloud unavailable.',true);}}

/* ═══ MEDICAL NOTES PROMPT IMAGE HELPERS ═══ */
function handleMNPromptImgFiles(key,files){if(!mnPromptImages[key])mnPromptImages[key]=[];const promises=Array.from(files).map(f=>compressImage(f,1200,.78).then(dataUrl=>({dataUrl,name:f.name})));Promise.all(promises).then(imgs=>{mnPromptImages[key].push(...imgs);renderMNPromptImgThumbs(key);const inp=document.getElementById('mnPromptImgInput_'+key);if(inp)inp.value='';});}
function renderMNPromptImgThumbs(key){const t=document.getElementById('mnPromptImgThumbs_'+key);if(!t)return;t.innerHTML=(mnPromptImages[key]||[]).map((img,i)=>`<div class="mn-img-thumb-wrap"><img class="mn-img-thumb" src="${img.dataUrl}" onclick="openImgPreview('${img.dataUrl}')" title="${esc(img.name)}"><button class="mn-img-remove" onclick="removeMNPromptImage('${key}',${i})" title="Remove">\xd7</button></div>`).join('');}
function removeMNPromptImage(key,idx){if(!mnPromptImages[key])return;mnPromptImages[key].splice(idx,1);renderMNPromptImgThumbs(key);}
function handleMNPromptReaderFile(key,file){if(!file)return;const reader=new FileReader();reader.onload=e=>{mnPromptInlineDataUrl[key]=e.target.result;document.getElementById('mnPromptReaderImg_'+key).src=e.target.result;document.getElementById('mnPromptInlineReader_'+key).style.display='block';document.getElementById('mnPromptReaderResultArea_'+key).style.display='none';document.getElementById('mnPromptBtnAdd_'+key).style.display='none';document.getElementById('mnPromptReaderCtx_'+key).value='';document.getElementById('mnPromptReaderCtx_'+key).style.display='none';document.getElementById('mnPromptCtxToggle_'+key).textContent='+ Add context (optional)';document.getElementById('mnPromptReaderInput_'+key).value='';};reader.readAsDataURL(file);}
function toggleMNPromptCtx(key){const ca=document.getElementById('mnPromptReaderCtx_'+key);const ct=document.getElementById('mnPromptCtxToggle_'+key);const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
async function transcribeMNPromptImage(key,taId){if(!mnPromptInlineDataUrl[key]){toast('No image loaded.',true);return;}const context=(document.getElementById('mnPromptReaderCtx_'+key)?.value||'').trim();document.getElementById('mnPromptReaderLoader_'+key).style.display='block';document.getElementById('mnPromptReaderResultArea_'+key).style.display='none';document.getElementById('mnPromptBtnTranscribe_'+key).disabled=true;try{const text=await callVisionAPI(mnPromptInlineDataUrl[key],buildImagePrompt(context));if(text==='IMAGING_DETECTED'){window._imagingTarget='mnprompt_'+key;window._imagingTargetTaId=taId;document.getElementById('imagingContextModal').classList.add('open');}else{document.getElementById('mnPromptReaderResult_'+key).value=text;document.getElementById('mnPromptReaderResultArea_'+key).style.display='block';document.getElementById('mnPromptBtnAdd_'+key).style.display='';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('mnPromptReaderLoader_'+key).style.display='none';document.getElementById('mnPromptBtnTranscribe_'+key).disabled=false;}}
function appendMNPromptTranscription(key,taId){const text=document.getElementById('mnPromptReaderResult_'+key).value.trim();if(!text){toast('No transcription.',true);return;}const ta=document.getElementById(taId);if(!ta)return;const existing=ta.value.trim();ta.value=existing?(existing+'\n\n'+text):text;clearMNPromptReader(key);toast('Added to notes!');}
function clearMNPromptReader(key){mnPromptInlineDataUrl[key]=null;const ir=document.getElementById('mnPromptInlineReader_'+key);if(ir)ir.style.display='none';const ri=document.getElementById('mnPromptReaderInput_'+key);if(ri)ri.value='';const ra=document.getElementById('mnPromptReaderResultArea_'+key);if(ra)ra.style.display='none';const ba=document.getElementById('mnPromptBtnAdd_'+key);if(ba)ba.style.display='none';}
function buildMNPromptImgBarHTML(key,taId){return'<div class="mn-img-bar" style="margin-top:8px"><label class="mn-img-add-btn" for="mnPromptImgInput_'+key+'"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg> Add Images</label><input type="file" id="mnPromptImgInput_'+key+'" accept="image/*" multiple style="display:none" onchange="handleMNPromptImgFiles(\''+key+'\',this.files)"><div class="mn-img-thumbs" id="mnPromptImgThumbs_'+key+'"></div><label class="mn-img-add-btn" for="mnPromptReaderInput_'+key+'" style="background:var(--primary-light);border-color:rgba(26,86,219,.35);color:var(--primary)"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg> Read Image</label><input type="file" id="mnPromptReaderInput_'+key+'" accept="image/*" style="display:none" onchange="handleMNPromptReaderFile(\''+key+'\',this.files[0])"></div><div id="mnPromptInlineReader_'+key+'" class="mn-inline-reader"><div style="display:flex;align-items:flex-start;gap:12px;margin-bottom:10px"><img id="mnPromptReaderImg_'+key+'" class="mn-inline-reader-img" alt="" onclick="openImgPreview(this.src)" title="Click to enlarge"><div style="flex:1;min-width:0"><div style="font-size:.74rem;font-weight:700;color:var(--text-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.4px">Image loaded</div><button class="mn-context-toggle" id="mnPromptCtxToggle_'+key+'" onclick="toggleMNPromptCtx(\''+key+'\')">+ Add context (optional)</button><textarea id="mnPromptReaderCtx_'+key+'" class="mn-context-area" style="display:none" placeholder="E.g.: CBC from Jan 2024, chest X-ray..."></textarea></div></div><div id="mnPromptReaderLoader_'+key+'" style="display:none;padding:10px 0;text-align:center"><div class="mn-spinner" style="margin:0 auto 6px"></div><span style="font-size:.78rem;color:var(--text-muted)">Reading image...</span></div><div id="mnPromptReaderResultArea_'+key+'" style="display:none"><div style="font-size:.72rem;font-weight:700;color:var(--text-muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:.4px">Transcription</div><textarea id="mnPromptReaderResult_'+key+'" class="mn-inline-reader-result" placeholder="Transcription will appear here..."></textarea></div><div class="mn-actions" style="margin-top:8px"><button class="mn-btn mn-btn-primary" id="mnPromptBtnTranscribe_'+key+'" onclick="transcribeMNPromptImage(\''+key+'\',\''+taId+'\')" style="font-size:.78rem;padding:7px 14px">Transcribe</button><button class="mn-btn mn-btn-outline" id="mnPromptBtnAdd_'+key+'" onclick="appendMNPromptTranscription(\''+key+'\',\''+taId+'\')" style="display:none;font-size:.78rem;padding:7px 14px">Add to Notes</button><button class="mn-btn mn-btn-outline" onclick="clearMNPromptReader(\''+key+'\')" style="font-size:.78rem;padding:7px 14px">Close</button></div></div>';}

/* ═══ MEDICAL NOTES CARD BUILDER & HELPERS ═══ */
function buildMNCardHTML(mnid,html,stamp){return'<div class="mn-medical-notes-generated" id="'+mnid+'" style="margin-top:20px;border:2px solid #9333ea;border-radius:var(--radius-lg);padding:18px;background:rgba(147,51,234,.05);position:relative"><button onclick="deleteMedicalNotes(\''+mnid+'\')" style="position:absolute;top:10px;right:10px;width:28px;height:28px;border-radius:50%;border:1px solid rgba(192,57,43,.3);background:rgba(192,57,43,.1);color:#c0392b;cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center" title="Delete">&times;</button><div class="mn-output-label" style="color:#9333ea;display:flex;align-items:center;gap:8px">Medical Notes #'+medicalNotesCount+' <span class="mn-badge" style="background:rgba(147,51,234,.15);color:#9333ea">Generated</span><button class="mn-btn mn-btn-outline" id="btnMNRead_'+mnid+'" onclick="toggleMNReadAloud(\''+mnid+'\')" title="Read Aloud" style="margin-left:auto;width:34px;height:34px;padding:0;display:inline-flex;align-items:center;justify-content:center;opacity:.7;flex-shrink:0;border-radius:50%;margin-right:36px"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:17px;height:17px"><polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M15.54 8.46a5 5 0 010 7.07"/><path d="M19.07 4.93a10 10 0 010 14.14"/></svg></button><span id="ttsStatusMN_'+mnid+'" style="display:none;font-size:.7rem;color:var(--text-muted);margin-left:6px;font-style:italic"></span></div><div class="mn-card"><div class="mn-report" id="report_'+mnid+'" contenteditable="true" spellcheck="true">'+html+stamp+'</div><div class="mn-img-bar" style="margin-top:12px"><label class="mn-img-add-btn" for="mnImgInput_'+mnid+'"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg> Add Images</label><input type="file" id="mnImgInput_'+mnid+'" accept="image/*" multiple style="display:none" onchange="handleMNImgFiles(\''+mnid+'\',this.files)"><div class="mn-img-thumbs" id="mnImgThumbs_'+mnid+'"></div><label class="mn-img-add-btn" for="mnInlineReaderInput_'+mnid+'" style="background:var(--primary-light);border-color:rgba(26,86,219,.35);color:var(--primary)"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg> Read Image</label><input type="file" id="mnInlineReaderInput_'+mnid+'" accept="image/*" style="display:none" onchange="handleMNInlineReaderFile(\''+mnid+'\',this.files[0])"></div><div id="mnInlineReader_'+mnid+'" class="mn-inline-reader"><div style="display:flex;align-items:flex-start;gap:12px;margin-bottom:10px"><img id="mnInlineReaderImg_'+mnid+'" class="mn-inline-reader-img" alt="" onclick="openImgPreview(this.src)" title="Click to enlarge"><div style="flex:1;min-width:0"><div style="font-size:.74rem;font-weight:700;color:var(--text-muted);margin-bottom:6px;text-transform:uppercase;letter-spacing:.4px">Image loaded</div><button class="mn-context-toggle" id="mnInlineCtxToggle_'+mnid+'" onclick="toggleMNInlineContext(\''+mnid+'\')">+ Add context (optional)</button><textarea id="mnInlineReaderContext_'+mnid+'" class="mn-context-area" style="display:none" placeholder="E.g.: CBC, chest X-ray..."></textarea></div></div><div id="mnInlineReaderLoader_'+mnid+'" style="display:none;padding:10px 0;text-align:center"><div class="mn-spinner" style="margin:0 auto 6px"></div><span style="font-size:.78rem;color:var(--text-muted)">Reading image...</span></div><div id="mnInlineReaderResultArea_'+mnid+'" style="display:none"><div style="font-size:.72rem;font-weight:700;color:var(--text-muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:.4px">Transcription</div><textarea id="mnInlineReaderResult_'+mnid+'" class="mn-inline-reader-result" placeholder="Transcription will appear here..."></textarea></div><div class="mn-actions" style="margin-top:8px"><button class="mn-btn mn-btn-primary" id="mnBtnTranscribeInline_'+mnid+'" onclick="transcribeMNInlineImage(\''+mnid+'\')" style="font-size:.78rem;padding:7px 14px">Transcribe</button><button class="mn-btn mn-btn-outline" id="mnBtnAddToReport_'+mnid+'" onclick="appendMNTranscription(\''+mnid+'\')" style="display:none;font-size:.78rem;padding:7px 14px">Add to Report</button><button class="mn-btn mn-btn-outline" onclick="clearMNInlineReader(\''+mnid+'\')" style="font-size:.78rem;padding:7px 14px">Close</button></div></div><div class="mn-actions" style="margin-top:12px;border-top:1px solid var(--border);padding-top:14px"><button class="mn-btn mn-btn-edit" onclick="toggleMNEditPanel(\''+mnid+'\')">AI Edit</button><button class="mn-btn" style="background:var(--success-light);color:var(--success);border:1px solid rgba(13,124,68,.18)" onclick="toggleMNEmailPanel(\''+mnid+'\')">Email</button><div class="mn-export-wrap" id="mnExportWrap_'+mnid+'"><button class="mn-btn mn-btn-outline" onclick="toggleMNExport(\''+mnid+'\')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Export <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="width:11px;height:11px;margin-left:1px"><polyline points="6 9 12 15 18 9"/></svg></button><div class="mn-export-menu"><button onclick="downloadMedicalNotesPDF(\''+mnid+'\');closeMNExport(\''+mnid+'\')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg> PDF</button><button onclick="downloadMNDocx(\''+mnid+'\');closeMNExport(\''+mnid+'\')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg> Word</button></div></div><button class="mn-btn mn-btn-copy" onclick="copyMedicalNotes(\''+mnid+'\')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg> Copy</button><button class="mn-btn" style="background:rgba(147,51,234,.15);color:#9333ea;border:1px solid rgba(147,51,234,.25)" onclick="showMedicalNotesFromGenerated(\''+mnid+'\')">+ Medical Notes</button></div><div class="mn-edit-panel" id="mnEditPanel_'+mnid+'"><div style="font-size:.8rem;font-weight:600;color:var(--edit);margin-bottom:8px">Describe changes for AI</div><textarea id="mnEditInstr_'+mnid+'" class="mn-edit-textarea" placeholder="e.g.: Change the diagnosis to..."></textarea><div class="mn-edit-actions"><button class="mn-btn mn-btn-apply" onclick="applyMNEdit(\''+mnid+'\')">Apply</button><button class="mn-btn mn-btn-cancel-edit" onclick="toggleMNEditPanel(\''+mnid+'\')">Cancel</button></div></div><div class="mn-email-panel" id="mnEmailPanel_'+mnid+'"><div class="mn-email-title">Send report via email</div><input type="email" class="mn-email-input" id="mnEmailTo_'+mnid+'" placeholder="recipient@email.com"><div class="mn-email-btns"><button class="mn-btn mn-btn-send" onclick="sendMNEmail(\''+mnid+'\')">Send</button><button class="mn-btn mn-btn-cancel-edit" onclick="toggleMNEmailPanel(\''+mnid+'\')">Cancel</button></div></div><details class="mn-notes-panel" style="margin-top:10px"><summary>&#128221; Personal Notes (not exported)</summary><textarea class="mn-notes-textarea" id="mnPersonalNotes_'+mnid+'" placeholder="Private notes about this Medical Note..." oninput="saveMNPersonalNote(\''+mnid+'\')"></textarea></details></div></div>';}
function handleMNImgFiles(mnid,files){if(!mnImages[mnid])mnImages[mnid]=[];const promises=Array.from(files).map(f=>compressImage(f,1200,.78).then(dataUrl=>({dataUrl,name:f.name})));Promise.all(promises).then(imgs=>{mnImages[mnid].push(...imgs);renderMNImageThumbs(mnid);document.getElementById('mnImgInput_'+mnid).value='';syncMNImagesInReport(mnid);});}
function renderMNImageThumbs(mnid){const t=document.getElementById('mnImgThumbs_'+mnid);if(!t)return;t.innerHTML=(mnImages[mnid]||[]).map((img,i)=>`<div class="mn-img-thumb-wrap"><img class="mn-img-thumb" src="${img.dataUrl}" onclick="openImgPreview('${img.dataUrl}')" title="${esc(img.name)}"><button class="mn-img-remove" onclick="removeMNImage('${mnid}',${i})" title="Remove">\xd7</button></div>`).join('');}
function removeMNImage(mnid,idx){if(!mnImages[mnid])return;mnImages[mnid].splice(idx,1);renderMNImageThumbs(mnid);syncMNImagesInReport(mnid);}
function syncMNImagesInReport(mnid){const rc=document.getElementById('report_'+mnid);if(!rc)return;const ex=rc.querySelector('.mn-case-images');if(ex)ex.remove();const imgs=mnImages[mnid]||[];if(imgs.length){const h='<div class="mn-case-images"><div class="mn-case-images-title"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="15" height="15"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg> Clinical Images</div><div class="mn-case-images-grid">'+imgs.map(img=>'<img src="'+img.dataUrl+'" onclick="openImgPreview(\''+img.dataUrl+'\')" alt="'+esc(img.name)+'" style="max-width:100%;max-height:280px;border-radius:8px;border:1px solid var(--border);cursor:pointer;object-fit:contain">').join('')+'</div></div>';rc.insertAdjacentHTML('beforeend',h);}}
function handleMNInlineReaderFile(mnid,file){if(!file)return;const reader=new FileReader();reader.onload=e=>{mnInlineDataUrl[mnid]=e.target.result;document.getElementById('mnInlineReaderImg_'+mnid).src=e.target.result;document.getElementById('mnInlineReader_'+mnid).style.display='block';document.getElementById('mnInlineReaderResultArea_'+mnid).style.display='none';document.getElementById('mnBtnAddToReport_'+mnid).style.display='none';document.getElementById('mnInlineReaderContext_'+mnid).value='';document.getElementById('mnInlineReaderContext_'+mnid).style.display='none';document.getElementById('mnInlineCtxToggle_'+mnid).textContent='+ Add context (optional)';document.getElementById('mnInlineReaderInput_'+mnid).value='';};reader.readAsDataURL(file);}
function toggleMNInlineContext(mnid){const ca=document.getElementById('mnInlineReaderContext_'+mnid);const ct=document.getElementById('mnInlineCtxToggle_'+mnid);const vis=ca.style.display!=='none';ca.style.display=vis?'none':'block';ct.textContent=vis?'+ Add context (optional)':'- Hide context';if(!vis)ca.focus();}
async function transcribeMNInlineImage(mnid){if(!mnInlineDataUrl[mnid]){toast('No image loaded.',true);return;}const context=(document.getElementById('mnInlineReaderContext_'+mnid)?.value||'').trim();document.getElementById('mnInlineReaderLoader_'+mnid).style.display='block';document.getElementById('mnInlineReaderResultArea_'+mnid).style.display='none';document.getElementById('mnBtnTranscribeInline_'+mnid).disabled=true;try{const text=await callVisionAPI(mnInlineDataUrl[mnid],buildImagePrompt(context));if(text==='IMAGING_DETECTED'){document.getElementById('imagingContextModal').classList.add('open');window._imagingTarget='mn_'+mnid;}else{document.getElementById('mnInlineReaderResult_'+mnid).value=text;document.getElementById('mnInlineReaderResultArea_'+mnid).style.display='block';document.getElementById('mnBtnAddToReport_'+mnid).style.display='';toast('Image read!');}}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('mnInlineReaderLoader_'+mnid).style.display='none';document.getElementById('mnBtnTranscribeInline_'+mnid).disabled=false;}}
function appendMNTranscription(mnid){const text=document.getElementById('mnInlineReaderResult_'+mnid).value.trim();if(!text){toast('No transcription.',true);return;}const rep=document.getElementById('report_'+mnid);rep.innerHTML+='<p>'+esc(text)+'</p>';clearMNInlineReader(mnid);toast('Added to report!');}
function clearMNInlineReader(mnid){mnInlineDataUrl[mnid]=null;document.getElementById('mnInlineReader_'+mnid).style.display='none';document.getElementById('mnInlineReaderInput_'+mnid).value='';document.getElementById('mnInlineReaderResultArea_'+mnid).style.display='none';document.getElementById('mnBtnAddToReport_'+mnid).style.display='none';}
function toggleMNEditPanel(mnid){document.getElementById('mnEditPanel_'+mnid).classList.toggle('active');if(document.getElementById('mnEditPanel_'+mnid).classList.contains('active'))document.getElementById('mnEditInstr_'+mnid).focus();}
async function applyMNEdit(mnid){const ins=document.getElementById('mnEditInstr_'+mnid).value.trim();if(!ins){toast('Describe changes.',true);return;}document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Applying changes...';try{const current=document.getElementById('report_'+mnid).innerHTML;const html=await callAPI(EDIT_PROMPT.replace('{{CURRENT_REPORT}}',current).replace('{{EDIT_INSTRUCTIONS}}',ins));document.getElementById('report_'+mnid).innerHTML=html;applyReportTypoTo(document.getElementById('report_'+mnid));document.getElementById('mnEditPanel_'+mnid).classList.remove('active');document.getElementById('mnEditInstr_'+mnid).value='';toast('Applied.');}catch(e){toast('Error: '+e.message,true);}finally{document.getElementById('loader').classList.remove('active');}}
function toggleMNEmailPanel(mnid){const p=document.getElementById('mnEmailPanel_'+mnid);p.classList.toggle('active');if(p.classList.contains('active')){const ef=document.getElementById('mnEmailTo_'+mnid);if(!ef.value.trim())ef.value=S.email||'';ef.focus();}}
async function sendMNEmail(mnid){const to=document.getElementById('mnEmailTo_'+mnid).value.trim();if(!to||!to.includes('@')){toast('Enter a valid email.',true);return;}const h=document.getElementById('report_'+mnid).innerHTML;try{await emailjs.send('service_juj0v5c','template_rw4cwfl',{to_email:to,subject:'Medical Notes',report_html:h});toast('Sent to '+to);document.getElementById('mnEmailPanel_'+mnid).classList.remove('active');}catch(e){toast('Error: '+(e.text||e.message||e),true);}}
const mnTtsReading={},mnTtsAudio={};
async function toggleMNReadAloud(mnid){
  const btn=document.getElementById('btnMNRead_'+mnid);
  const statusEl=document.getElementById('ttsStatusMN_'+mnid);
  if(mnTtsReading[mnid]){if(mnTtsAudio[mnid]){mnTtsAudio[mnid].pause();delete mnTtsAudio[mnid];}mnTtsReading[mnid]=false;if(btn)ttsSetState(btn,statusEl,'idle');return;}
  const text=document.getElementById('report_'+mnid)?.innerText||'';
  if(!text.trim()){toast('No report to read.',true);return;}
  mnTtsReading[mnid]=true;if(btn)ttsSetState(btn,statusEl,'loading');
  try{
    const res=await fetch(PROXY+'/tts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({input:text.slice(0,4096),voice:'alloy',model:'tts-1'})});
    if(!res.ok)throw new Error();
    const url=URL.createObjectURL(await res.blob());
    const audio=new Audio(url);mnTtsAudio[mnid]=audio;
    if(btn)ttsSetState(btn,statusEl,'playing');
    const reset=()=>{URL.revokeObjectURL(url);mnTtsReading[mnid]=false;delete mnTtsAudio[mnid];const b=document.getElementById('btnMNRead_'+mnid);const s=document.getElementById('ttsStatusMN_'+mnid);if(b)ttsSetState(b,s,'idle');};
    audio.onended=reset;audio.onerror=reset;audio.play();
  }catch(e){mnTtsReading[mnid]=false;if(btn)ttsSetState(btn,statusEl,'idle');toast('Read Aloud unavailable.',true);}
}
function toggleMNExport(mnid){document.getElementById('mnExportWrap_'+mnid).classList.toggle('open');}
function closeMNExport(mnid){document.getElementById('mnExportWrap_'+mnid)?.classList.remove('open');}
function downloadMNDocx(mnid){const h=document.getElementById('report_'+mnid).innerHTML;const doc='<!DOCTYPE html><html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="UTF-8"><style>@page{size:letter;margin:2.54cm}body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6}h2{font-size:13pt;font-weight:bold;border-bottom:1px solid #ddd;padding-bottom:4pt}p{margin:3pt 0}strong{font-weight:bold}</style></head><body>'+h+'</body></html>';const blob=new Blob(['\ufeff'+doc],{type:'application/msword'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='Medical_Notes.doc';document.body.appendChild(a);a.click();setTimeout(()=>{document.body.removeChild(a);URL.revokeObjectURL(url);},250);toast('Word ready.');}
function saveMNPersonalNote(mnid){try{const all=JSON.parse(localStorage.getItem('mn_pnotes_mn')||'{}');all[mnid]=document.getElementById('mnPersonalNotes_'+mnid).value;localStorage.setItem('mn_pnotes_mn',JSON.stringify(all));}catch{}}

/* ═══ MEDICAL NOTES FROM ADMISSION ═══ */
function showMedicalNotesPrompt(){const promptArea=document.getElementById('medicalNotesPromptArea');if(!promptArea.querySelector('.mn-img-bar')){document.getElementById('medicalNotesInstructions').insertAdjacentHTML('afterend',buildMNPromptImgBarHTML('main','medicalNotesInstructions'));}promptArea.style.display='block';attachMiniMic('medicalNotesInstructions');document.getElementById('medicalNotesInstructions').focus();promptArea.scrollIntoView({behavior:'smooth'});}function hideMedicalNotesPrompt(){document.getElementById('medicalNotesPromptArea').style.display='none';}
async function generateMedicalNotes(sourceId){
if(window.generatingMedicalNotes){toast('Please wait, already generating...',true);return;}
const instructions=document.getElementById('medicalNotesInstructions').value.trim();
if(!instructions){toast('Enter additional clinical information.',true);return;}
let prevReport='';
if(sourceId){prevReport=document.querySelector('#'+sourceId+' .mn-report')?.innerText||'';}
else{prevReport=document.getElementById('reportContent').innerText||'';}
window.generatingMedicalNotes=true;
document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Generating Medical Notes — please wait...';
try{
const notesPrompt=buildPrompt('notes');
const combinedInput='PREVIOUS ADMISSION/REPORT INFORMATION:\n'+prevReport+'\n\nNEW CLINICAL INFORMATION:\n'+instructions;
const html=await callAPI(notesPrompt.replace('{{USER_TEXT}}',combinedInput));
medicalNotesCount++;
const mnid='medicalnotes_'+medicalNotesCount;
const container=document.getElementById('medicalNotesContainer');
const stamp='<div class="mn-doctor-stamp">'+getDoctorStampHTML()+'</div>';
container.insertAdjacentHTML('beforeend',buildMNCardHTML(mnid,html,stamp));
applyReportTypoTo(document.getElementById('report_'+mnid));
if(mnPromptImages['main']?.length){mnImages[mnid]=[...mnPromptImages['main']];mnPromptImages['main']=[];renderMNPromptImgThumbs('main');renderMNImageThumbs(mnid);syncMNImagesInReport(mnid);}
document.getElementById('medicalNotesPromptArea').style.display='none';document.getElementById('medicalNotesInstructions').value='';
document.getElementById(mnid).scrollIntoView({behavior:'smooth'});toast('Medical Notes generated.');
}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');window.generatingMedicalNotes=false;}}
function showMedicalNotesFromGenerated(sourceId){
const container=document.getElementById(sourceId);
let promptArea=container.querySelector('.mn-medical-notes-prompt-inline');
if(promptArea){promptArea.style.display='block';promptArea.querySelector('textarea').focus();return;}
container.insertAdjacentHTML('beforeend','<div class="mn-medical-notes-prompt-inline" style="margin-top:14px;padding:14px;background:rgba(147,51,234,.08);border:1px solid rgba(147,51,234,.2);border-radius:var(--radius)"><div style="font-size:.8rem;font-weight:700;color:#9333ea;margin-bottom:8px">Generate New Medical Notes</div><textarea class="mn-followup-prompt" style="min-height:60px" placeholder="Enter additional clinical information..."></textarea>'+buildMNPromptImgBarHTML(sourceId,'miniMicTa_'+sourceId)+'<div class="mn-actions" style="margin-top:10px"><button class="mn-btn" style="background:#9333ea;color:#fff;font-size:.78rem;padding:7px 14px" onclick="generateMedicalNotesFromSource(\''+sourceId+'\')">Generate</button><button class="mn-btn mn-btn-outline" style="font-size:.78rem;padding:7px 14px" onclick="this.closest(\'.mn-medical-notes-prompt-inline\').style.display=\'none\'">Cancel</button></div></div>');
const inlineTa=container.querySelector('.mn-medical-notes-prompt-inline textarea');inlineTa.id='miniMicTa_'+sourceId;attachMiniMic(inlineTa.id);inlineTa.focus();}
async function generateMedicalNotesFromSource(sourceId){
if(window.generatingMedicalNotes){toast('Please wait, already generating...',true);return;}
const container=document.getElementById(sourceId);
const textarea=container.querySelector('.mn-medical-notes-prompt-inline textarea');
const instructions=textarea.value.trim();
if(!instructions){toast('Enter additional clinical information.',true);return;}
const prevReport=container.querySelector('.mn-report').innerText||'';
window.generatingMedicalNotes=true;
document.getElementById('loader').classList.add('active');document.getElementById('loaderText').textContent='Generating Medical Notes — please wait...';
try{
const notesPrompt=buildPrompt('notes');
const combinedInput='PREVIOUS REPORT INFORMATION:\n'+prevReport+'\n\nNEW CLINICAL INFORMATION:\n'+instructions;
const html=await callAPI(notesPrompt.replace('{{USER_TEXT}}',combinedInput));
medicalNotesCount++;
const mnid='medicalnotes_'+medicalNotesCount;
const mainContainer=document.getElementById('medicalNotesContainer');
const stamp='<div class="mn-doctor-stamp">'+getDoctorStampHTML()+'</div>';
mainContainer.insertAdjacentHTML('beforeend',buildMNCardHTML(mnid,html,stamp));
applyReportTypoTo(document.getElementById('report_'+mnid));
if(mnPromptImages[sourceId]?.length){mnImages[mnid]=[...mnPromptImages[sourceId]];mnPromptImages[sourceId]=[];renderMNPromptImgThumbs(sourceId);renderMNImageThumbs(mnid);syncMNImagesInReport(mnid);}
container.querySelector('.mn-medical-notes-prompt-inline').style.display='none';
textarea.value='';
document.getElementById(mnid).scrollIntoView({behavior:'smooth'});toast('Medical Notes generated.');
}catch(err){toast('Error: '+err.message,true);}finally{document.getElementById('loader').classList.remove('active');window.generatingMedicalNotes=false;}}
function copyMedicalNotes(mnid){const el=document.querySelector('#'+mnid+' .mn-report');if(!el)return;navigator.clipboard.writeText(el.innerText).then(()=>toast('Copied.')).catch(()=>toast('Copy failed.',true));}
async function downloadMedicalNotesPDF(mnid){const el=document.querySelector('#'+mnid+' .mn-report');if(!el)return;toast('Preparing PDF...');try{const canvas=await html2canvas(el,{scale:2,backgroundColor:'#fff'});const{jsPDF}=window.jspdf;const pdf=new jsPDF('p','mm','a4');const pw=pdf.internal.pageSize.getWidth()-20;const ih=canvas.height*pw/canvas.width;pdf.addImage(canvas.toDataURL('image/png'),'PNG',10,10,pw,ih);pdf.save('Medical_Notes_'+mnid+'.pdf');toast('PDF ready.');}catch{toast('PDF error.',true);}}
async function readMedicalNotes(mnid){toggleMNReadAloud(mnid);}
function emailMedicalNotes(mnid){toast('Use copy and paste to email.',false);}
function deleteMedicalNotes(mnid){showConfirm('Delete this Medical Note?',ok=>{if(ok){const el=document.getElementById(mnid);if(el)el.remove();toast('Medical Note deleted.');}});}
function applyReportTypoTo(rep){if(!rep)return;const sh=curSheet();rep.style.fontFamily=sh.options?.fontFamily||'Arial, sans-serif';const t=sh.options?.typo||{h2:{size:16,bold:true,color:'#000000',underline:false},strong:{size:14,bold:true,color:'#000000',underline:false},p:{size:14,bold:false,color:'#000000',underline:false}};const h2=typeof t.h2==='number'?{size:t.h2,bold:true,color:'#000000',underline:false}:t.h2;const st=typeof t.strong==='number'?{size:t.strong,bold:true,color:'#000000',underline:false}:t.strong;const pp=typeof t.p==='number'?{size:t.p,bold:false,color:'#000000',underline:false}:t.p;rep.querySelectorAll('h2').forEach(el=>{el.style.fontSize=h2.size+'px';el.style.fontWeight=h2.bold?'700':'400';el.style.color=h2.color||'';el.style.textDecoration=h2.underline?'underline':'none';});rep.querySelectorAll('strong').forEach(el=>{el.style.fontSize=st.size+'px';el.style.fontWeight=st.bold?'700':'400';el.style.color=st.color||'';el.style.textDecoration=st.underline?'underline':'none';});rep.querySelectorAll('p').forEach(el=>{el.style.fontSize=pp.size+'px';el.style.fontWeight=pp.bold?'700':'400';el.style.color=pp.color||'';el.style.textDecoration=pp.underline?'underline':'none';});}

/* ═══ DEFAULT PROMPT FUNCTIONS ═══ */
function savePromptNormal(){savePBO();toast('Prompt saved.');}
function savePromptAsDefault(){showConfirm('<strong>⚠️ Save All Prompts as Default?</strong><br><br>All prompt configurations for <strong>every sheet</strong> will be saved as your permanent defaults. This replaces any previously saved defaults.<br><br>You can restore individual sheets anytime with "Reset to Default" in Advanced settings.',ok=>{if(!ok)return;savePBO();S.sheets.forEach(sh=>{const key='mn_default_prompt_'+sh.id;const data={sections:JSON.parse(JSON.stringify(sh.sections)),options:JSON.parse(JSON.stringify(sh.options))};localStorage.setItem(key,JSON.stringify(data));});toast('✓ All prompts saved as default.');});}
function loadDefaultPrompt(){const key='mn_default_prompt_'+pbSheetId;const saved=localStorage.getItem(key);if(!saved){toast('No default prompt saved for this sheet.',true);return;}showConfirm('<strong>Load Default Prompt?</strong><br><br>This will replace current settings with your saved default for <strong>'+esc(getSheet(pbSheetId).name)+'</strong>.',ok=>{if(!ok)return;try{const data=JSON.parse(saved);const sh=getSheet(pbSheetId);sh.sections=JSON.parse(JSON.stringify(data.sections));sh.options=JSON.parse(JSON.stringify(data.options));saveS(S);loadPBO();renderPBS();toast('✓ Default prompt loaded.');}catch{toast('Error loading default.',true);}});}

/* INIT */
renderModeTabs();switchMode('notes');updateFilterTypeOptions();renderSidebar();renderWelcome();renderBookmarks();
